// ProductDetailScreen.js
import React, { useState } from 'react';
import {
  View,
  StyleSheet,
  ScrollView,
  Image,
} from 'react-native';
import { Text, Button, IconButton } from 'react-native-paper';
import { MaterialCommunityIcons as Icon } from '@expo/vector-icons';

export default function ProductDetailScreen({ route, navigation }) {
  const { product } = route.params;
  const [quantity, setQuantity] = useState(1);

  const incrementQuantity = () => setQuantity(q => q + 1);
  const decrementQuantity = () => setQuantity(q => q > 1 ? q - 1 : 1);

  const addToCart = () => {
    alert(`Added ${quantity} ${product.unit} of ${product.name} to cart`);
    navigation.goBack();
  };

  return (
    <View style={styles.container}>
      <View style={styles.header}>
        <IconButton
          icon="arrow-left"
          size={24}
          onPress={() => navigation.goBack()}
        />
        <Text style={styles.headerTitle}>Product Details</Text>
        <IconButton icon="share-variant" size={24} />
      </View>

      <ScrollView style={styles.content}>
        <View style={styles.imageContainer}>
          <Text style={styles.productEmoji}>{product.image}</Text>
          {product.organic && (
            <View style={styles.organicBadge}>
              <Icon name="leaf" size={16} color="#2E7D32" />
              <Text style={styles.organicText}>Organic</Text>
            </View>
          )}
        </View>

        <View style={styles.detailsContainer}>
          <Text style={styles.productName}>{product.name}</Text>
          <Text style={styles.category}>{product.category}</Text>

          <View style={styles.priceRow}>
            <Text style={styles.price}>₹{product.price}</Text>
            <Text style={styles.unit}>/{product.unit}</Text>
          </View>

          <View style={styles.ratingRow}>
            <Icon name="star" size={20} color="#FFC107" />
            <Text style={styles.rating}>{product.rating}</Text>
            <Text style={styles.reviews}>(120 reviews)</Text>
          </View>

          <View style={styles.section}>
            <Text style={styles.sectionTitle}>Farmer Information</Text>
            <View style={styles.farmerCard}>
              <Icon name="account-circle" size={50} color="#2E7D32" />
              <View style={styles.farmerInfo}>
                <Text style={styles.farmerName}>{product.farmer}</Text>
                <View style={styles.locationRow}>
                  <Icon name="map-marker" size={14} color="#666" />
                  <Text style={styles.location}> {product.location}</Text>
                </View>
              </View>
              <IconButton icon="message-text" size={24} />
            </View>
          </View>

          <View style={styles.section}>
            <Text style={styles.sectionTitle}>Description</Text>
            <Text style={styles.description}>
              Fresh, high-quality {product.name.toLowerCase()} directly from the farm.
              Harvested daily to ensure maximum freshness and nutritional value.
              {product.organic && ' Grown using 100% organic farming methods without synthetic pesticides or fertilizers.'}
            </Text>
          </View>

          <View style={styles.section}>
            <Text style={styles.sectionTitle}>Available Stock</Text>
            <Text style={styles.stock}>{product.stock} {product.unit} in stock</Text>
          </View>
        </View>
      </ScrollView>

      <View style={styles.bottomBar}>
        <View style={styles.quantityContainer}>
          <Text style={styles.quantityLabel}>Quantity</Text>
          <View style={styles.quantityControls}>
            <IconButton
              icon="minus"
              size={20}
              onPress={decrementQuantity}
              style={styles.quantityButton}
            />
            <Text style={styles.quantityText}>{quantity}</Text>
            <IconButton
              icon="plus"
              size={20}
              onPress={incrementQuantity}
              style={styles.quantityButton}
            />
          </View>
        </View>
        <Button
          mode="contained"
          onPress={addToCart}
          style={styles.addToCartButton}
          buttonColor="#2E7D32"
        >
          Add to Cart
        </Button>
      </View>
    </View>
  );
}

const styles = StyleSheet.create({
  container: {
    flex: 1,
    backgroundColor: '#fff',
  },
  header: {
    flexDirection: 'row',
    alignItems: 'center',
    justifyContent: 'space-between',
    paddingTop: 50,
    paddingHorizontal: 10,
    backgroundColor: '#fff',
    elevation: 2,
  },
  headerTitle: {
    fontSize: 18,
    fontWeight: 'bold',
  },
  content: {
    flex: 1,
  },
  imageContainer: {
    height: 250,
    backgroundColor: '#f0f0f0',
    justifyContent: 'center',
    alignItems: 'center',
    position: 'relative',
  },
  productEmoji: {
    fontSize: 120,
  },
  organicBadge: {
    position: 'absolute',
    top: 20,
    right: 20,
    backgroundColor: '#E8F5E9',
    flexDirection: 'row',
    alignItems: 'center',
    paddingHorizontal: 12,
    paddingVertical: 6,
    borderRadius: 20,
  },
  organicText: {
    marginLeft: 5,
    color: '#2E7D32',
    fontSize: 12,
    fontWeight: '600',
  },
  detailsContainer: {
    padding: 20,
  },
  productName: {
    fontSize: 24,
    fontWeight: 'bold',
    color: '#333',
  },
  category: {
    fontSize: 14,
    color: '#666',
    marginTop: 5,
  },
  priceRow: {
    flexDirection: 'row',
    alignItems: 'baseline',
    marginTop: 15,
  },
  price: {
    fontSize: 28,
    fontWeight: 'bold',
    color: '#2E7D32',
  },
  unit: {
    fontSize: 16,
    color: '#666',
    marginLeft: 5,
  },
  ratingRow: {
    flexDirection: 'row',
    alignItems: 'center',
    marginTop: 10,
  },
  rating: {
    fontSize: 16,
    fontWeight: '600',
    marginLeft: 5,
  },
  reviews: {
    fontSize: 14,
    color: '#666',
    marginLeft: 5,
  },
  section: {
    marginTop: 25,
  },
  sectionTitle: {
    fontSize: 18,
    fontWeight: 'bold',
    marginBottom: 10,
  },
  farmerCard: {
    flexDirection: 'row',
    alignItems: 'center',
    backgroundColor: '#f9f9f9',
    padding: 15,
    borderRadius: 12,
  },
  farmerInfo: {
    flex: 1,
    marginLeft: 15,
  },
  farmerName: {
    fontSize: 16,
    fontWeight: '600',
  },
  locationRow: {
    flexDirection: 'row',
    alignItems: 'center',
    marginTop: 3,
  },
  location: {
    fontSize: 13,
    color: '#666',
  },
  description: {
    fontSize: 14,
    color: '#666',
    lineHeight: 22,
  },
  stock: {
    fontSize: 16,
    color: '#2E7D32',
    fontWeight: '600',
  },
  bottomBar: {
    flexDirection: 'row',
    padding: 20,
    backgroundColor: '#fff',
    borderTopWidth: 1,
    borderTopColor: '#e0e0e0',
    alignItems: 'center',
  },
  quantityContainer: {
    marginRight: 15,
  },
  quantityLabel: {
    fontSize: 12,
    color: '#666',
    marginBottom: 5,
  },
  quantityControls: {
    flexDirection: 'row',
    alignItems: 'center',
    backgroundColor: '#f0f0f0',
    borderRadius: 8,
  },
  quantityButton: {
    margin: 0,
  },
  quantityText: {
    fontSize: 16,
    fontWeight: '600',
    marginHorizontal: 15,
  },
  addToCartButton: {
    flex: 1,
  },
});
